// Parse EACH competitor's plain-text JSON output into a clean object.
const results = [];

for (const item of $input.all()) {
  let raw = item.json.output ?? item.json.text ?? '';
  if (typeof raw !== 'string') raw = JSON.stringify(raw);

  raw = raw.replace(/```(?:json)?/gi, '').trim();
  const firstBrace = raw.indexOf('{');
  const lastBrace = raw.lastIndexOf('}');
  if (firstBrace !== -1 && lastBrace !== -1 && lastBrace > firstBrace) {
    raw = raw.slice(firstBrace, lastBrace + 1);
  }
  raw = raw.replace(/,\s*([}\]])/g, '$1');

  let parsed;
  try {
    parsed = JSON.parse(raw);
  } catch (err) {
    results.push({
      json: {
        name: item.json.competitor?.name ?? 'Unknown',
        pricing: 'Not publicly available',
        key_features: [],
        positioning: 'Parse error — see _parse_error',
        recent_news: ['No significant recent news identified'],
        threat_level: 'Low',
        sources: [],
        _parse_error: err.message,
        _raw_output: item.json.output ?? item.json.text ?? ''
      }
    });
    continue;
  }

  // Normalize / guardrails
  if (!Array.isArray(parsed.key_features)) parsed.key_features = [];
  parsed.key_features = parsed.key_features.slice(0, 5);
  if (!Array.isArray(parsed.recent_news) || parsed.recent_news.length === 0) {
    parsed.recent_news = ['No significant recent news identified'];
  }
  if (!Array.isArray(parsed.sources)) parsed.sources = [];
  if (!['High', 'Medium', 'Low'].includes(parsed.threat_level)) {
    parsed.threat_level = 'Medium';
  }
  if (!parsed.pricing) parsed.pricing = 'Not publicly available';

  results.push({ json: parsed });
}

return results;

// Flatten EACH competitor object into a single row for Google Sheets.
const results = [];

let target = '';
let industry = '';
let focus = '';
try {
  const trigger = $('When Executed by Another Workflow').first().json;
  target = trigger.target_company ?? '';
  industry = trigger.inferred_industry ?? '';
  focus = trigger.focus_area ?? '';
} catch (e) { /* context not available, leave blank */ }

for (const item of $input.all()) {
  const c = item.json;
  results.push({
    json: {
      run_timestamp: new Date().toISOString(),
      target_company: target,
      inferred_industry: industry,
      focus_area: focus,
      competitor_name: c.name ?? '',
      pricing: c.pricing ?? '',
      key_features: Array.isArray(c.key_features) ? c.key_features.join('\n') : (c.key_features ?? ''),
      positioning: c.positioning ?? '',
      recent_news: Array.isArray(c.recent_news) ? c.recent_news.join('\n') : (c.recent_news ?? ''),
      digital_presence: c.digital_presence ?? '',
      threat_level: c.threat_level ?? '',
      sources: Array.isArray(c.sources) ? c.sources.join('\n') : (c.sources ?? ''),
      parse_error: c._parse_error ?? '',
      _competitor: c
    }
  });
}

return results;

// Reshape Aggregate output into the shape Synthesis expects.
const agg = $input.first().json;

// Aggregate puts the competitor objects under "data"
const competitors = Array.isArray(agg.data) ? agg.data : [];

// Strip the internal _competitor wrapper if present (each item may be {_competitor:{...}} or the object itself)
const cleanCompetitors = competitors.map(c => c._competitor ? c._competitor : c);

// Pull the original context from the trigger
let target = '';
let industry = '';
let focus = '';
try {
  const trigger = $('When Executed by Another Workflow').first().json;
  target = trigger.target_company ?? '';
  industry = trigger.inferred_industry ?? '';
  focus = trigger.focus_area ?? '';
} catch (e) { /* leave blank */ }

return [{
  json: {
    target_company: target,
    inferred_industry: industry,
    focus_area: focus,
    competitors: cleanCompetitors
  }
}];
